import os
import io
import pandas as pd
import boto3

source = "datagov/texas-department-of-criminal-justice-receives-fy-2019/files/rows.txt"
bucket = "lakeqa-yc4103-datalake"
local_path = source if os.path.exists(source) else "/tmp/k123_data_cache/" + source

if os.path.exists(local_path):
    df = pd.read_csv(local_path, sep=",", engine="c", low_memory=False)
else:
    obj = boto3.client("s3").get_object(Bucket=bucket, Key=source)
    df = pd.read_csv(io.BytesIO(obj["Body"].read()), sep=",", engine="c", low_memory=False)
node_4_answer = ['Harris', 'Dallas', 'Bexar']
node_5_answer = ['Harris', 'Dallas', 'Bexar', 'Travis']
node_6_answer = ['Harris', 'Dallas', 'Bexar']

def norm_county(x):
    return str(x).strip().title()

def extract_county_names(v):
    if isinstance(v, dict):
        return [norm_county(k) for k in v.keys()]
    if isinstance(v, list):
        return [norm_county(x) for x in v]
    return [norm_county(v)]

# Task variants: some nodes depend on node_4..node_6, others on node_1..node_3.
dep_values = []
for nm in ["node_4_answer", "node_5_answer", "node_6_answer"]:
    if nm in locals():
        dep_values.append(locals()[nm])
if len(dep_values) < 3:
    dep_values = []
    for nm in ["node_1_answer", "node_2_answer", "node_3_answer"]:
        if nm in locals():
            dep_values.append(locals()[nm])

candidates = set()
if len(dep_values) >= 3:
    candidates = set(extract_county_names(dep_values[0])) & set(extract_county_names(dep_values[1])) & set(extract_county_names(dep_values[2]))

counts = df["County"].dropna().astype(str).map(norm_county)
counts = counts[counts.isin(candidates)].value_counts()
answer = {county: int(counts.get(county, 0)) for county in sorted(candidates, key=lambda c: (-int(counts.get(c, 0)), c))}

